glsl.vertex:
varying vec2 vUv;
void main(){
 vUv = uv;
 gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
}

glsl.fragment:
precision highp float;
varying vec2 vUv;
uniform float uTime;
uniform float uCoverage;
uniform float uEdgeSoftness;
uniform float uGrainStrength;
uniform float uBlueSeamOffset;
uniform float uGateWidth;
float hash(vec2 p){ return fract(sin(dot(p, vec2(127.1, 311.7))) * 43758.5453123); }
float noise(vec2 p){ vec2 i=floor(p); vec2 f=fract(p); vec2 u=f*f*(3.0-2.0*f); return mix(mix(hash(i),hash(i+vec2(1.0,0.0)),u.x),mix(hash(i+vec2(0.0,1.0)),hash(i+vec2(1.0,1.0)),u.x),u.y); }
float ellipseBand(vec2 p, vec2 r, float w){ float d=length(p/r); return smoothstep(1.0+w,1.0,d)-smoothstep(1.0,1.0-w,d); }
float softRect(vec2 p, vec2 halfSize, float soft){ vec2 q=abs(p)-halfSize; float outD=length(max(q,0.0))+min(max(q.x,q.y),0.0); return 1.0-smoothstep(0.0,soft,outD); }
void main(){
 vec2 uv=vUv;
 vec2 p=(uv-0.5)*vec2(1.0,1.28);
 vec3 cream=vec3(0.918,0.867,0.725);
 vec3 red=vec3(0.788,0.290,0.133);
 vec3 orange=vec3(0.878,0.604,0.157);
 vec3 gold=vec3(0.718,0.565,0.197);
 vec3 blue=vec3(0.193,0.373,0.624);
 vec3 umber=vec3(0.445,0.190,0.110);
 float paperEdge=softRect(p, vec2(0.455*uCoverage,0.585*uCoverage), 0.018);
 float grain=noise(uv*220.0)+0.45*noise(uv*63.0);
 vec3 col=cream*(0.93+0.10*grain);
 vec2 temple=p-vec2(0.0,0.03);
 float bands=0.0;
 bands+=ellipseBand(temple, vec2(0.36,0.48), 0.020);
 bands+=ellipseBand(temple, vec2(0.29,0.39), 0.018);
 bands+=ellipseBand(temple, vec2(0.22,0.30), 0.016);
 bands+=ellipseBand(temple, vec2(0.145,0.205), 0.014);
 float upper= smoothstep(-0.34,-0.05,p.y);
 float handmade=0.82+0.18*noise(uv*95.0+3.0);
 col=mix(col, mix(red,orange,0.34+0.26*noise(uv*9.0)), clamp(bands*upper*handmade,0.0,0.92));
 float gate=softRect(vec2(p.x,p.y+0.03), vec2(uGateWidth,0.46), 0.010);
 float gateCore=softRect(vec2(p.x,p.y+0.03), vec2(uGateWidth*0.42,0.50), 0.006);
 col=mix(col,gold,gate*0.72);
 col=mix(col,vec3(0.82,0.68,0.31),gateCore*0.42);
 float seamX=uBlueSeamOffset+0.030*sin((p.y+0.45)*9.0)+0.010*sin((p.y+0.2)*31.0);
 float seam=1.0-smoothstep(0.006,0.022,abs(p.x-seamX));
 float seamMask=smoothstep(-0.48,-0.32,p.y)*(1.0-smoothstep(0.52,0.59,p.y));
 col=mix(col,blue,seam*seamMask*0.88);
 float baseLine=softRect(vec2(p.x,p.y+0.465), vec2(0.38,0.007),0.006);
 col=mix(col,umber,baseLine*0.45);
 col=mix(vec3(0.08,0.065,0.052),col,paperEdge);
 col*=0.975+uGrainStrength*(grain-0.65);
 gl_FragColor=vec4(col,1.0);
}

precision highp float;
varying vec2 vUv;
uniform float uTime;
uniform float uCount;
uniform float uHeight;
uniform float uBaseY;
uniform float uVariation;
float hash(float n){ return fract(sin(n*91.71)*43758.5453); }
float stroke(vec2 p, float x, float h, float w){ float y0=uBaseY; float y1=uBaseY+h; float taper=mix(0.55,1.0,smoothstep(y0,y1,p.y))*(1.0-0.30*smoothstep(y0,y1,p.y)); float dx=abs(p.x-x); float body=1.0-smoothstep(w*taper,w*taper+0.008,dx); float yr=smoothstep(y0,y0+0.018,p.y)*(1.0-smoothstep(y1-0.018,y1,p.y)); return body*yr; }
void main(){
 vec2 uv=vUv;
 vec2 p=vec2((uv.x-0.5),uv.y);
 vec3 red=vec3(0.71,0.20,0.12);
 vec3 gold=vec3(0.75,0.57,0.22);
 float a=0.0;
 vec3 col=vec3(0.0);
 for(int i=0;i<32;i++){
 if(float(i)>=uCount) break;
 float fi=float(i);
 float x=mix(-0.39,0.39,(fi+0.5)/uCount)+0.010*(hash(fi)-0.5);
 float h=uHeight*(0.62+uVariation*hash(fi+4.0));
 float w=0.006+0.006*hash(fi+9.0);
 float s=stroke(p,x,h,w);
 vec3 c=mix(red,gold,hash(fi+19.0)*0.55);
 col+=c*s*(0.55+0.35*hash(fi+29.0));
 a=max(a,s*0.72);
 }
 gl_FragColor=vec4(col,max(0.0,min(0.78,a)));
}

precision highp float;
varying vec2 vUv;
uniform float uTime;
uniform float uPanelGap;
uniform float uFractureLean;
float hash(vec2 p){return fract(sin(dot(p,vec2(41.3,289.1)))*43758.5453);} 
float ring(vec2 p, vec2 r, float w){float d=length(p/r);return smoothstep(1.0+w,1.0,d)-smoothstep(1.0,1.0-w,d);} 
float rect(vec2 p, vec2 h, float s){vec2 q=abs(p)-h;float d=length(max(q,0.0))+min(max(q.x,q.y),0.0);return 1.0-smoothstep(0.0,s,d);} 
void main(){
 vec2 p=(vUv-0.5)*vec2(1.0,1.22); vec3 cream=vec3(0.91,0.85,0.69); vec3 red=vec3(0.75,0.25,0.13); vec3 orange=vec3(0.88,0.55,0.12); vec3 gold=vec3(0.70,0.54,0.19); vec3 blue=vec3(0.17,0.34,0.60); float g=hash(floor(vUv*260.0)); vec3 col=cream*(0.95+0.06*g);
 float paper=rect(p,vec2(0.46,0.57),0.02); float gaps=1.0-max(rect(vec2(p.x+0.17,p.y),vec2(uPanelGap,0.56),0.006),rect(vec2(p.x-0.17,p.y),vec2(uPanelGap,0.56),0.006));
 for(int k=0;k<3;k++){ float cx=-0.31+float(k)*0.31; vec2 q=p-vec2(cx,0.03); float rr=ring(q,vec2(0.12,0.28),0.018)+ring(q,vec2(0.08,0.20),0.014); col=mix(col,mix(red,orange,float(k)*0.28),clamp(rr,0.0,0.8)); }
 float gate=rect(vec2(p.x,p.y+0.03),vec2(0.026,0.49),0.007); col=mix(col,gold,gate*0.86);
 float sx=-0.07+uFractureLean*p.y+0.012*sin(p.y*22.0); float seam=1.0-smoothstep(0.006,0.019,abs(p.x-sx)); col=mix(col,blue,seam*0.82);
 col=mix(vec3(0.09,0.07,0.05),col,paper*gaps); gl_FragColor=vec4(col,1.0);
}
